var n="\n\n/* Reset */\n~ {\n    box-sizing: border-box;\n    color: var(--ok_fg);\n    background: var(--ok_bg);\n    font-family: var(--ok_font-family);\n    font-size: var(--ok_font-size);\n    line-height: var(--ok_line-height-base);\n}\n\n~ *,\n~ *::before,\n~ *::after {\n    box-sizing: inherit;\n    min-width: 0;\n    min-height: 0;\n}\n\n/* Inline elements */\n~ hr {\n    border: none;\n    border-top: var(--ok_border);\n    margin: var(--ok_space) 0;\n}\n\n~ img {\n    max-width: 100%;\n    height: auto;\n    display: block;\n}\n\n~ code {\n    font-family: var(--ok_font-family-monospace, monospace);\n    background: var(--ok_bg-muted);\n    padding: 0 var(--ok_space-xs);\n    border-radius: var(--ok_space-xs);\n}\n\n/* Headings */\n~ h1,\n    ~ h2,\n    ~ h3,\n    ~ h4,\n    ~ h5,\n    ~ h6 {\n    color: var(--ok_fg);\n    margin: calc(var(--ok_space) * 2) 0 var(--ok_space);\n    font-weight: var(--ok_font-weight-bold);\n    line-height: 1.2;\n}\n~ h1 { font-size: calc(var(--ok_font-size) * 2); }\n~ h2 { font-size: calc(var(--ok_font-size) * 1.75); }\n~ h3 { font-size: calc(var(--ok_font-size) * 1.5); }\n~ h4 { font-size: calc(var(--ok_font-size) * 1.25); }\n~ h5 { font-size: var(--ok_font-size); }\n~ h6 { font-size: calc(var(--ok_font-size) * 0.875); }\n\n/* Baseline for form elements */\n~ button,\n~ input[type=file]::file-selector-button,\n~ input[type=file]::-webkit-file-upload-button,\n~ input,\n~ select,\n~ textarea {\n    font-family: inherit;\n    font-size: inherit;\n    font-weight: inherit;\n    line-height: inherit;\n    font-variant-numeric: tabular-nums;\n    background: var(--ok_bg);\n    padding: var(--ok_space-sm);\n    color: var(--ok_fg);\n    border: var(--ok_border);\n    border-radius: var(--ok_space-xs);\n    box-shadow: var(--ok_shadow);\n    transition: var(--ok_transition);\n}\n\n/* Links */\n~ a {\n    color: var(--ok_fg-accent);\n    text-decoration: underline;\n}\n~ a:hover {\n    color: color-mix(in srgb, var(--ok_fg-accent) 80%, var(--ok_fg));\n    text-decoration: none;\n}\n\n/* ───────────────────────────────────────────────────── */\n/* Flavors: accent / secondary / muted */\n/* ───────────────────────────────────────────────────── */\n~ .accent {\n    background: var(--ok_bg-accent);\n    color: var(--ok_fg-accent);\n    border: var(--ok_border-accent);\n}\n~ .accent:hover {\n    background: color-mix(in srgb, var(--ok_bg-accent) 90%, var(--ok_fg-accent));\n}\n~ button.accent.active {\n    background: var(--ok_bg);\n}\n\n~ .muted {\n    background: var(--ok_bg-muted);\n    color: var(--ok_fg-muted);\n    border: var(--ok_border-muted);\n}\n~ .muted:hover {\n    background: color-mix(in srgb, var(--ok_bg-muted) 90%, var(--ok_fg-accent));\n}\n\n~ .secondary {\n    background: var(--ok_bg-secondary);\n    color: var(--ok_fg-secondary);\n    border: var(--ok_border-secondary);\n}\n~ button.secondary.active {\n    background: var(--ok_bg);\n}\n~ .secondary:hover {\n    background: color-mix(in srgb, var(--ok_bg-secondary) 90%, black);\n}";export{n as default};
